import{_ as r,C as a,o,c as i,E as n,w as d,a as s,a0 as c}from"./chunks/framework.CkNTPv-z.js";const g=JSON.parse('{"title":"France Healthcare & HRT","description":"Transgender healthcare access in France","frontmatter":{"layout":"doc","title":"France Healthcare & HRT","description":"Transgender healthcare access in France"},"headers":[],"relativePath":"europe/france/healthcare.md","filePath":"europe/france/healthcare.md","lastUpdated":null}'),l={name:"europe/france/healthcare.md"};function h(p,t,u,m,f,y){const e=a("Badge");return o(),i("div",null,[n(e,{variant:"green"},{default:d(()=>[...t[0]||(t[0]=[s("Informed Consent",-1)])]),_:1}),t[1]||(t[1]=c('<h1 id="healthcare-hrt-in-france" tabindex="-1">Healthcare &amp; HRT in France <a class="header-anchor" href="#healthcare-hrt-in-france" aria-label="Permalink to &quot;Healthcare &amp; HRT in France&quot;">​</a></h1><h2 id="access-model" tabindex="-1">Access Model <a class="header-anchor" href="#access-model" aria-label="Permalink to &quot;Access Model&quot;">​</a></h2><p>France operates broadly on an informed consent model. Since 2010, the Haute Autorité de Santé (HAS) removed the requirement for a psychiatric diagnosis to access transgender healthcare. In practice, a GP or endocrinologist can prescribe HRT under an informed consent framework, though some doctors still prefer a letter from a psychologist.</p><p>Public health insurance (Sécurité Sociale) covers transgender healthcare. ALD (Affection Longue Durée) status is available for trans-related care, providing 100% reimbursement for many treatments.</p><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>Le Centre LGBTQ+</td><td>Paris</td><td>Community health, HRT referrals</td></tr><tr><td>Hôpital Saint-Louis</td><td>Paris</td><td>Trans healthcare, endocrinology</td></tr><tr><td>Hôpital de la Conception</td><td>Marseille</td><td>Gender clinic, HRT, surgery</td></tr><tr><td>CHU de Lyon</td><td>Lyon</td><td>Multidisciplinary trans healthcare</td></tr><tr><td>Spot Longoë</td><td>Bordeaux</td><td>Trans health, HRT, community support</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><p>As an EU member, France recognises prescriptions from other EU/EEA countries. Non-EU immigrants must see a French doctor for a local prescription. A medical summary in French documenting your HRT history is highly recommended.</p><p>A 3-month supply of HRT medications for personal use is generally permitted with a valid prescription.</p><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><p>Gender-affirming surgeries are covered by Sécurité Sociale under ALD status, including top surgery, bottom surgery, hysterectomy, and some facial feminisation procedures. Major surgical centres are in Paris, Lyon, and Marseille. Wait times are 6-18 months for most procedures.</p><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Public Cost</th><th>Private Cost</th></tr></thead><tbody><tr><td>GP visit</td><td>€25 (70% reimbursed)</td><td>€50-80</td></tr><tr><td>Endocrinologist</td><td>€30 (70% reimbursed)</td><td>€80-150</td></tr><tr><td>HRT (monthly)</td><td>€10-30</td><td>€40-70</td></tr><tr><td>Top Surgery</td><td>Covered (ALD)</td><td>€5,000-10,000</td></tr><tr><td>Bottom Surgery</td><td>Covered (ALD)</td><td>€12,000-25,000</td></tr></tbody></table>',13))])}const T=r(l,[["render",h]]);export{g as __pageData,T as default};
